INSERT INTO user_role (user_id, role_id) SELECT u.id, r.id FROM [user] u, role r WHERE u.username = 'bob_jones' AND r.name = 'moderator';
INSERT INTO user_role (user_id, role_id) SELECT u.id, r.id FROM [user] u, role r WHERE u.username = 'charlie_dev' AND r.name = 'student';

rollback.sql:
DELETE FROM user_role
WHERE user_id IN (
SELECT id FROM [user]
WHERE username IN ('alice_smith', 'bob_jones', 'charlie_dev')
);
